import React, { useState, useRef, useEffect } from 'react';
import * as XLSX from 'xlsx';
import dbService from '../services/dbService';
import syncService from '../services/syncService';

// ----------------------------- INITIAL MOCK DATA -----------------------------
const DEFAULT_OFFICE_DATA = {
  'PSTO-Ilocos Norte': {
    warning_signals: {},
    general_weather: '',
    related_incidents: 0,
    casualties: 0,
    power_status: '',
    communication_lines: '',
    damage_facilities: '',
    work_suspension: false,
    assistance_provided: '',
    remark: '',
    remark_related_incidents: '',
    remark_casualties: '',
    remark_power_status: '',
    remark_communication_lines: '',
    remark_damage_facilities: '',
    remark_work_suspension: '',
    remark_assistance_provided: '',
    municipalities: ['Laoag City', 'Batac City', 'Pagudpud']
  },
  'PSTO-Ilocos Sur': {
    warning_signals: {},
    general_weather: '',
    related_incidents: 0,
    casualties: 0,
    power_status: '',
    communication_lines: '',
    damage_facilities: '',
    work_suspension: false,
    assistance_provided: '',
    remark: '',
    remark_related_incidents: '',
    remark_casualties: '',
    remark_power_status: '',
    remark_communication_lines: '',
    remark_damage_facilities: '',
    remark_work_suspension: '',
    remark_assistance_provided: '',
    municipalities: ['Vigan City', 'Candon City', 'Santa Maria']
  },
  'PSTO-La Union': {
    warning_signals: {},
    general_weather: '',
    related_incidents: 0,
    casualties: 0,
    power_status: '',
    communication_lines: '',
    damage_facilities: '',
    work_suspension: false,
    assistance_provided: '',
    remark: '',
    remark_related_incidents: '',
    remark_casualties: '',
    remark_power_status: '',
    remark_communication_lines: '',
    remark_damage_facilities: '',
    remark_work_suspension: '',
    remark_assistance_provided: '',
    municipalities: ['San Fernando', 'Bauang', 'Agoo', 'Luna', 'Bacnotan', 'Bangar', 'San Juan']
  },
  'PSTO-Pangasinan': {
    warning_signals: {},
    general_weather: '',
    related_incidents: 0,
    casualties: 0,
    power_status: '',
    communication_lines: '',
    damage_facilities: '',
    work_suspension: false,
    assistance_provided: '',
    remark: '',
    remark_related_incidents: '',
    remark_casualties: '',
    remark_power_status: '',
    remark_communication_lines: '',
    remark_damage_facilities: '',
    remark_work_suspension: '',
    remark_assistance_provided: '',
    municipalities: ['Lingayen', 'Dagupan', 'Alaminos']
  },
};

const DEFAULT_EVENTS = [
  { id: 1, name: 'CALOY', date: 'Jun 1, 2026', type: 'Tropical Cyclone', alertLevel: 'RED', deployment: 'Deployed', provinces: ['Ilocos Norte'], status: 'active', trackPositions: '13.0N 121.2E → 13.8N 122.1E', intensity: '95 kph / 52 kt', imageUrl: '', startDateTime: '2026-06-01T08:00', endDateTime: '2026-06-03T18:00', category: 'Super Typhoon', reportLink: '', related_incidents: 1, remark_related_incidents: '', casualties: 0, remark_casualties: '', power_status: '3 - Partial blackout', remark_power_status: '', communication_lines: 'Limited', remark_communication_lines: '', damage_facilities: '2 - Minor', remark_damage_facilities: '', work_suspension: false, remark_work_suspension: '', assistance_provided: 'Food packs', remark_assistance_provided: '', rejectionReason: '' },
  { id: 2, name: 'BASYANG', date: 'Jun 1, 2026', type: 'Tropical Cyclone', alertLevel: 'RED', deployment: 'Draft', provinces: ['Ilocos Norte'], status: 'draft', reportLink: 'https://pubfiles.pagasa.dost.gov.ph/pagasaweb/files/tamss/weather/tcprelimsummary/PAGASA_Prelim_2026_BASYANG.pdf', trackPositions: '12.6N 120.8E → 13.4N 121.6E', intensity: '90 kph / 49 kt', imageUrl: '', startDateTime: '2026-06-01T10:00', endDateTime: '', category: 'Typhoon', related_incidents: 0, remark_related_incidents: '', casualties: 0, remark_casualties: '', power_status: '', remark_power_status: '', communication_lines: '', remark_communication_lines: '', damage_facilities: '', remark_damage_facilities: '', work_suspension: false, remark_work_suspension: '', assistance_provided: '', remark_assistance_provided: '', rejectionReason: '' },
  { id: 3, name: 'ADA', date: 'Jun 1, 2026', type: 'Tropical Cyclone', alertLevel: 'BLUE', deployment: 'Draft', provinces: ['Ilocos Norte', 'Ilocos Sur', 'La Union', 'Pangasinan'], status: 'draft', trackPositions: '', intensity: '', imageUrl: '', startDateTime: '2026-06-01T12:00', endDateTime: '', category: 'Tropical Storm', related_incidents: 0, remark_related_incidents: '', casualties: 0, remark_casualties: '', power_status: '', remark_power_status: '', communication_lines: '', remark_communication_lines: '', damage_facilities: '', remark_damage_facilities: '', work_suspension: false, remark_work_suspension: '', assistance_provided: '', remark_assistance_provided: '', rejectionReason: '' }
];

const DEFAULT_USERS = [
  { id: 1, name: 'Admin User', email: 'admin@dostregion1.ph', office: 'PSTO-La Union', role: 'SADMIN', status: 'Active', password: 'admin123' },
  { id: 2, name: 'Regional Admin', email: 'admin-ilocosnorte@dostregion1.ph', office: 'PSTO-Ilocos Norte', role: 'ADMIN', status: 'Active', password: 'admin123' },
  { id: 3, name: 'General User', email: 'user-ilocossur@dostregion1.ph', office: 'PSTO-Ilocos Sur', role: 'USER', status: 'Active', password: 'user123' },
  { id: 4, name: 'La Union User', email: 'user-launion@dostregion1.ph', office: 'PSTO-La Union', role: 'USER', status: 'Active', password: 'user123' },
  { id: 5, name: 'Pangasinan User', email: 'user-pangasinan@dostregion1.ph', office: 'PSTO-Pangasinan', role: 'USER', status: 'Active', password: 'user123' },
  { id: 6, name: 'Ilocos Sur User', email: 'user-ilocossur2@dostregion1.ph', office: 'PSTO-Ilocos Sur', role: 'USER', status: 'Active', password: 'user123' },
  { id: 7, name: 'Ilocos Norte User', email: 'user-ilocosnorte@dostregion1.ph', office: 'PSTO-Ilocos Norte', role: 'USER', status: 'Active', password: 'user123' },
];

// Helper functions
const loadFromStorage = (key, defaultValue) => {
  const stored = localStorage.getItem(key);
  if (stored) {
    try { return JSON.parse(stored); } catch(e) { return defaultValue; }
  }
  return defaultValue;
};

const saveToStorage = (key, data) => localStorage.setItem(key, JSON.stringify(data));

const archiveOldEvents = (events) => {
  const sevenDaysAgo = new Date();
  sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7);
  return events.map(event => {
    if (event.status !== 'archived' && event.endDateTime) {
      const endDate = new Date(event.endDateTime);
      if (endDate < sevenDaysAgo) {
        return { ...event, status: 'archived', deployment: event.deployment === 'Deployed' ? 'Draft' : event.deployment };
      }
    }
    return event;
  });
};

// Live weather fetch
const fetchLiveWeather = async () => {
  const lat = 16.5;
  const lon = 120.5;
  try {
    const response = await fetch(
      `https://api.open-meteo.com/v1/forecast?latitude=${lat}&longitude=${lon}&current_weather=true&timezone=Asia/Manila`
    );
    const data = await response.json();
    if (data.current_weather) {
      const w = data.current_weather;
      const temp = w.temperature;
      const weatherCode = w.weathercode;
      let condition = '';
      if (weatherCode === 0) condition = 'Clear sky';
      else if (weatherCode === 1 || weatherCode === 2) condition = 'Partly cloudy';
      else if (weatherCode === 3) condition = 'Overcast';
      else if (weatherCode >= 45 && weatherCode <= 49) condition = 'Fog';
      else if (weatherCode >= 51 && weatherCode <= 67) condition = 'Drizzle / Rain';
      else if (weatherCode >= 71 && weatherCode <= 77) condition = 'Snow';
      else if (weatherCode >= 80 && weatherCode <= 99) condition = 'Rain / Thunderstorm';
      else condition = 'Unknown';
      return { temp: Math.round(temp), condition, windSpeed: w.windspeed };
    }
  } catch (err) {
    console.error('Weather fetch failed:', err);
  }
  return null;
};

const Dashboard = ({ onLogout, currentUser }) => {
  // ----------------------------- STATE DECLARATIONS -----------------------------
  const [officesData, setOfficesData] = useState({});
  const [events, setEvents] = useState([]);
  const [users, setUsers] = useState([]);
  const [pendingReports, setPendingReports] = useState([]);
  const [notifications, setNotifications] = useState([]);
  const [liveWeather, setLiveWeather] = useState(null);
  const [weatherLoading, setWeatherLoading] = useState(true);
  const [loading, setLoading] = useState(true);

  const [activeMenu, setActiveMenu] = useState('dashboard');
  const [selectedOffice, setSelectedOffice] = useState(currentUser?.office || 'PSTO-La Union');
  const [editMode, setEditMode] = useState(false);
  const [formData, setFormData] = useState(null);
  const [newMunicipality, setNewMunicipality] = useState('');
  const [newSignal, setNewSignal] = useState(1);
  const [searchTerm, setSearchTerm] = useState('');
  const [statusFilter, setStatusFilter] = useState('all');
  const [showAddModal, setShowAddModal] = useState(false);
  const [showDetailsModal, setShowDetailsModal] = useState(false);
  const [selectedEvent, setSelectedEvent] = useState(null);
  const [isEditingEvent, setIsEditingEvent] = useState(false);
  const [isEditingReportLink, setIsEditingReportLink] = useState(false);
  const [reportLinkInput, setReportLinkInput] = useState('');
  const [showUserModal, setShowUserModal] = useState(false);
  const [isEditingUser, setIsEditingUser] = useState(false);
  const [userForm, setUserForm] = useState({ id: null, name: '', email: '', office: 'PSTO-La Union', role: 'USER', status: 'Active', password: '' });
  const [userSearchTerm, setUserSearchTerm] = useState('');
  const [imageModalSrc, setImageModalSrc] = useState('');
  const [showImageModal, setShowImageModal] = useState(false);
  const [toast, setToast] = useState({ message: '', type: 'info', visible: false });
  const [rejectReason, setRejectReason] = useState('');
  const [showRejectModal, setShowRejectModal] = useState(false);
  const [rejectEventId, setRejectEventId] = useState(null);
  const [showReportModal, setShowReportModal] = useState(false);
  const [reportFormData, setReportFormData] = useState(null);
  const [selectedReport, setSelectedReport] = useState(null);
  const [showReportReviewModal, setShowReportReviewModal] = useState(false);
  const [reportRejectReason, setReportRejectReason] = useState('');
  const toastTimerRef = useRef(null);
  const [expandedSections, setExpandedSections] = useState({
    warningSignals: true,
    generalWeather: true,
    effects: true,
    remarks: true
  });

  // Sync states
  const [syncing, setSyncing] = useState(false);
  const [lastSync, setLastSync] = useState(null);

  // New event form
  const [newEvent, setNewEvent] = useState({
    id: null, name: '', startDateTime: '', endDateTime: '',
    alertLevel: '', category: '', deployment: 'Draft', provinces: [],
    sendToAllUsers: false, reportLink: '', trackPositions: '', intensity: '',
    related_incidents: 0, remark_related_incidents: '', casualties: 0, remark_casualties: '',
    power_status: '', remark_power_status: '', communication_lines: '', remark_communication_lines: '',
    damage_facilities: '', remark_damage_facilities: '', work_suspension: false,
    remark_work_suspension: '', assistance_provided: '', remark_assistance_provided: '',
    imageUrl: '', status: 'pending', rejectionReason: ''
  });

  // ----------------------------- LOAD DATA FROM DATABASE -----------------------------
  useEffect(() => {
    const loadData = async () => {
      setLoading(true);
      try {
        const [loadedOffices, loadedEvents, loadedUsers, loadedReports, loadedNotifs, savedMenu] = await Promise.all([
          dbService.getOfficesData(),
          dbService.getEvents(),
          dbService.getUsers(),
          dbService.getPendingReports(),
          dbService.getNotifications(),
          dbService.getActiveMenu()
        ]);

        if (loadedOffices && Object.keys(loadedOffices).length > 0) {
          setOfficesData(loadedOffices);
        } else {
          setOfficesData(DEFAULT_OFFICE_DATA);
          await dbService.saveOfficesData(DEFAULT_OFFICE_DATA);
        }

        if (loadedEvents && loadedEvents.length > 0) {
          setEvents(archiveOldEvents(loadedEvents));
        } else {
          setEvents(DEFAULT_EVENTS);
          await dbService.saveEvents(DEFAULT_EVENTS);
        }

        if (loadedUsers && loadedUsers.length > 0) {
          setUsers(loadedUsers);
        } else {
          setUsers(DEFAULT_USERS);
          await dbService.saveUsers(DEFAULT_USERS);
        }

        if (loadedReports && loadedReports.length > 0) {
          setPendingReports(loadedReports);
        }

        if (loadedNotifs && loadedNotifs.length > 0) {
          setNotifications(loadedNotifs);
        }

        if (savedMenu) setActiveMenu(savedMenu);

        console.log('✅ Data loaded from database successfully');
      } catch (error) {
        console.error('Error loading from database:', error);
        // Fallback to localStorage
        setOfficesData(loadFromStorage('dash_officesData', DEFAULT_OFFICE_DATA));
        setEvents(archiveOldEvents(loadFromStorage('dash_events', DEFAULT_EVENTS)));
        setUsers(loadFromStorage('dash_users', DEFAULT_USERS));
        setPendingReports(loadFromStorage('dash_pendingReports', []));
        setNotifications(loadFromStorage('dash_notifications', []));
        setActiveMenu(loadFromStorage('dash_activeMenu', 'dashboard'));
      } finally {
        setLoading(false);
      }
    };

    loadData();
  }, []);

  // ----------------------------- SYNC SERVICE SETUP -----------------------------
  useEffect(() => {
    // Start auto-sync
    syncService.startAutoSync();

    // Listen for sync updates
    const unsubscribe = syncService.onSync((data) => {
      console.log('🔄 Received sync data:', data);

      if (data.offices && Object.keys(data.offices).length > 0) {
        setOfficesData(data.offices);
      }
      if (data.events) {
        setEvents(archiveOldEvents(data.events));
      }
      if (data.users) {
        setUsers(data.users);
      }
      if (data.reports) {
        setPendingReports(data.reports);
      }
      if (data.notifications) {
        setNotifications(data.notifications);
      }

      setLastSync(data.timestamp);
      setSyncing(false);
    });

    // Initial sync
    syncService.syncData();

    return () => {
      syncService.stopAutoSync();
      unsubscribe();
    };
  }, []);

  // ----------------------------- SAVE TO DATABASE WHEN DATA CHANGES -----------------------------
  useEffect(() => {
    const saveToDatabase = async () => {
      if (!loading) {
        try {
          await dbService.syncAllData({
            officesData,
            events,
            users,
            pendingReports,
            notifications,
            activeMenu
          });
          console.log('💾 Data saved to database');
        } catch (error) {
          console.error('Error saving to database:', error);
          // Fallback to localStorage
          saveToStorage('dash_officesData', officesData);
          saveToStorage('dash_events', events);
          saveToStorage('dash_users', users);
          saveToStorage('dash_pendingReports', pendingReports);
          saveToStorage('dash_notifications', notifications);
          saveToStorage('dash_activeMenu', activeMenu);
        }
      }
    };

    const timeoutId = setTimeout(saveToDatabase, 1000);
    return () => clearTimeout(timeoutId);
  }, [officesData, events, users, pendingReports, notifications, activeMenu, loading]);

  // Save active menu separately
  useEffect(() => {
    if (!loading) {
      dbService.saveActiveMenu(activeMenu);
      saveToStorage('dash_activeMenu', activeMenu);
    }
  }, [activeMenu, loading]);

  // Fetch live weather every 1 minute
  useEffect(() => {
    const getWeather = async () => {
      setWeatherLoading(true);
      const weather = await fetchLiveWeather();
      setLiveWeather(weather);
      setWeatherLoading(false);
    };
    getWeather();
    const interval = setInterval(getWeather, 60000);
    return () => clearInterval(interval);
  }, []);

  // Auto-archive events
  useEffect(() => {
    const archived = archiveOldEvents(events);
    if (JSON.stringify(archived) !== JSON.stringify(events)) setEvents(archived);
  }, [events]);

  // Role helpers
  const rawRole = currentUser?.role ?? '';
  const normalizedRole = rawRole.toString().trim().toUpperCase();
  const isSuperAdmin = normalizedRole.includes('SADMIN') || normalizedRole.includes('SUPER ADMIN') || normalizedRole.includes('SUPERADMIN');
  const isAdmin = !isSuperAdmin && (normalizedRole === 'ADMIN' || normalizedRole.includes('ADMIN'));
  const isUser = normalizedRole === 'USER';
  const canManageUsers = isSuperAdmin;
  const canEditEvents = isSuperAdmin || isAdmin;
  const canDeployEvents = isSuperAdmin;
  const canRejectEvents = isSuperAdmin;
  const canApproveReports = isSuperAdmin;

  useEffect(() => {
    if (isUser && currentUser?.office) setSelectedOffice(currentUser.office);
  }, [isUser, currentUser]);

  const allProvinces = ['Ilocos Norte', 'Ilocos Sur', 'La Union', 'Pangasinan'];
  const [activeEventId, setActiveEventId] = useState(() => {
    const active = events.find(e => e.deployment === 'Deployed')?.id || null;
    return active;
  });
  const activeEvent = events.find(e => e.id === activeEventId) || events.find(e => e.deployment === 'Deployed');

  const showToast = (message, type = 'info') => {
    if (toastTimerRef.current) clearTimeout(toastTimerRef.current);
    setToast({ message, type, visible: true });
    toastTimerRef.current = setTimeout(() => {
      setToast(prev => ({ ...prev, visible: false }));
      toastTimerRef.current = null;
    }, 3200);
  };

  // Add notification helper
  const addNotification = (title, message, type = 'info') => {
    const newNotif = {
      id: Date.now(),
      title,
      message,
      type,
      timestamp: new Date().toISOString(),
      read: false
    };
    setNotifications(prev => [newNotif, ...prev].slice(0, 50));
    showToast(message, type);
  };

  // Reset PSTO data to clean default
  const resetPSTODataForNewEvent = () => {
    const resetData = {};
    Object.keys(DEFAULT_OFFICE_DATA).forEach(office => {
      resetData[office] = {
        ...DEFAULT_OFFICE_DATA[office],
        warning_signals: {},
        general_weather: '',
        related_incidents: 0,
        casualties: 0,
        power_status: '',
        communication_lines: '',
        damage_facilities: '',
        work_suspension: false,
        assistance_provided: '',
        remark: '',
        remark_related_incidents: '',
        remark_casualties: '',
        remark_power_status: '',
        remark_communication_lines: '',
        remark_damage_facilities: '',
        remark_work_suspension: '',
        remark_assistance_provided: ''
      };
    });
    setOfficesData(resetData);
    addNotification('PSTO Data Reset', 'All PSTO warning signals and effects have been reset for the new event.', 'success');
  };

  // Reset / Export / Import
  const resetToDefaultData = () => {
    if (!isSuperAdmin) return;
    if (window.confirm('⚠️ Reset all data to factory defaults?')) {
      setOfficesData(DEFAULT_OFFICE_DATA);
      setEvents(archiveOldEvents(DEFAULT_EVENTS));
      setUsers(DEFAULT_USERS);
      setPendingReports([]);
      setNotifications([]);
      addNotification('System Reset', 'All data has been reset to factory defaults.', 'warning');
      showToast('Data reset to default.', 'success');
    }
  };

  const exportData = () => {
    const exportObj = { officesData, events, users, pendingReports, notifications, version: '1.5' };
    const dataStr = JSON.stringify(exportObj, null, 2);
    const blob = new Blob([dataStr], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `dost_dashboard_backup_${new Date().toISOString().slice(0,19)}.json`;
    a.click();
    URL.revokeObjectURL(url);
    addNotification('Data Exported', 'Backup exported successfully.', 'info');
    showToast('Data exported successfully.', 'success');
  };

  const importData = (e) => {
    const file = e.target.files[0];
    if (!file) return;
    const reader = new FileReader();
    reader.onload = (ev) => {
      try {
        const imported = JSON.parse(ev.target.result);
        if (imported.officesData) setOfficesData(imported.officesData);
        if (imported.events) setEvents(archiveOldEvents(imported.events));
        if (imported.users) setUsers(imported.users);
        if (imported.pendingReports) setPendingReports(imported.pendingReports);
        if (imported.notifications) setNotifications(imported.notifications);
        addNotification('Data Imported', 'Dashboard data has been restored from backup.', 'success');
        showToast('Data imported successfully.', 'success');
      } catch(err) {
        showToast('Invalid file format.', 'error');
      }
    };
    reader.readAsText(file);
    e.target.value = '';
  };

  const clearAllNotifications = () => {
    setNotifications([]);
    addNotification('Notifications Cleared', 'All notification history has been cleared.', 'info');
  };

  const markNotificationRead = (id) => {
    setNotifications(prev => prev.map(n => n.id === id ? { ...n, read: true } : n));
  };

  // ----------------------------- PSTO REPORT SUBMISSION -----------------------------
  const openReportModal = () => {
    const officeData = officesData[selectedOffice];
    setReportFormData(JSON.parse(JSON.stringify(officeData)));
    setShowReportModal(true);
  };

  const handleReportFieldChange = (field, value) => {
    setReportFormData(prev => ({ ...prev, [field]: value }));
  };

  const handleReportSignalChange = (mun, signal) => {
    setReportFormData(prev => ({
      ...prev,
      warning_signals: { ...prev.warning_signals, [mun]: parseInt(signal) }
    }));
  };

  const handleReportAddMunicipality = () => {
    if (newMunicipality.trim() && !reportFormData.municipalities.includes(newMunicipality)) {
      setReportFormData({
        ...reportFormData,
        municipalities: [...reportFormData.municipalities, newMunicipality],
        warning_signals: { ...reportFormData.warning_signals, [newMunicipality]: newSignal },
      });
      setNewMunicipality('');
      setNewSignal(1);
    }
  };

  const handleReportRemoveMunicipality = (mun) => {
    const updatedMuns = reportFormData.municipalities.filter(m => m !== mun);
    const updatedSignals = { ...reportFormData.warning_signals };
    delete updatedSignals[mun];
    setReportFormData({ ...reportFormData, municipalities: updatedMuns, warning_signals: updatedSignals });
  };

  const submitReport = () => {
    if (!reportFormData) return;
    const newReport = {
      id: Date.now(),
      office: selectedOffice,
      submittedBy: currentUser?.name || currentUser?.email,
      submittedAt: new Date().toISOString(),
      status: 'pending',
      data: reportFormData,
      remarks: ''
    };
    setPendingReports(prev => [newReport, ...prev]);
    setShowReportModal(false);
    setReportFormData(null);
    addNotification('Report Submitted', `${selectedOffice} has submitted a new report for approval.`, 'info');
    showToast('Report submitted for approval.', 'success');
  };

  const approveReport = (reportId) => {
    const report = pendingReports.find(r => r.id === reportId);
    if (!report) return;
    setOfficesData(prev => ({
      ...prev,
      [report.office]: { ...prev[report.office], ...report.data }
    }));
    setPendingReports(prev => prev.map(r => r.id === reportId ? { ...r, status: 'approved' } : r));
    addNotification('Report Approved', `Report from ${report.office} was approved and applied.`, 'success');
    showToast(`Report for ${report.office} approved and applied.`, 'success');
  };

  const openRejectReportModal = (report) => {
    setSelectedReport(report);
    setReportRejectReason('');
    setShowReportReviewModal(true);
  };

  const rejectReport = () => {
    if (!reportRejectReason.trim()) {
      showToast('Please provide a rejection reason.', 'warning');
      return;
    }
    setPendingReports(prev => prev.map(r => r.id === selectedReport.id ? { ...r, status: 'rejected', remarks: reportRejectReason } : r));
    addNotification('Report Rejected', `Report from ${selectedReport.office} was rejected. Reason: ${reportRejectReason}`, 'error');
    setShowReportReviewModal(false);
    setSelectedReport(null);
    setReportRejectReason('');
    showToast('Report rejected.', 'error');
  };

  // ----------------------------- EVENT MANAGEMENT -----------------------------
  const handleApproveEvent = (eventId) => {
    const event = events.find(e => e.id === eventId);
    setEvents(events.map(e => e.id === eventId ? { ...e, status: 'approved', rejectionReason: '' } : e));
    if (selectedEvent?.id === eventId) setSelectedEvent(prev => prev ? { ...prev, status: 'approved', rejectionReason: '' } : prev);
    addNotification('Event Approved', `Event ${event?.name} has been approved.`, 'success');
    showToast('Event approved and ready for deployment.', 'success');
  };

  const openRejectModal = (eventId) => {
    setRejectEventId(eventId);
    setRejectReason('');
    setShowRejectModal(true);
  };

  const confirmRejectEvent = () => {
    if (!rejectReason.trim()) { showToast('Please provide a rejection reason.', 'warning'); return; }
    const eventName = events.find(e => e.id === rejectEventId)?.name;
    setEvents(events.map(e => e.id === rejectEventId ? { ...e, status: 'rejected', rejectionReason: rejectReason, deployment: 'Draft' } : e));
    if (selectedEvent?.id === rejectEventId) setSelectedEvent(prev => prev ? { ...prev, status: 'rejected', rejectionReason: rejectReason } : prev);
    addNotification('Event Rejected', `Event ${eventName} was rejected. Reason: ${rejectReason}`, 'error');
    setShowRejectModal(false);
    setRejectEventId(null);
    setRejectReason('');
    showToast('Event rejected.', 'error');
  };

  const handleDeployEvent = (eventId) => {
    if (!canDeployEvents) { showToast('Only super admins can deploy events.', 'warning'); return; }
    const eventToDeploy = events.find(e => e.id === eventId);
    if (!eventToDeploy) return;
    if (eventToDeploy.status !== 'approved') { showToast('Only approved events can be deployed.', 'warning'); return; }
    if (!window.confirm('Deploy this event? It will become the active event.')) return;
    setEvents(events.map(e => ({
      ...e,
      deployment: e.id === eventId ? 'Deployed' : (e.deployment === 'Deployed' ? 'Draft' : e.deployment),
      status: e.id === eventId ? 'active' : (e.status === 'active' ? 'draft' : e.status)
    })));
    setActiveEventId(eventId);
    addNotification('Event Deployed', `Event ${eventToDeploy.name} is now the active typhoon.`, 'success');
    showToast('Event deployed.', 'success');
  };

  const handleAddEvent = () => {
    if (!canEditEvents && !isEditingEvent) { showToast('Only admins can add/edit events.', 'warning'); return; }
    if (!newEvent.name) { showToast('Event name is required.', 'warning'); return; }
    if (isEditingEvent && newEvent.id) {
      const formattedDate = newEvent.startDateTime ? new Date(newEvent.startDateTime).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : (newEvent.date || new Date().toLocaleDateString());
      const provinces = newEvent.sendToAllUsers ? allProvinces : newEvent.provinces;
      setEvents(events.map(e => e.id === newEvent.id ? ({ ...e, ...newEvent, provinces, date: formattedDate, type: e.type || 'Tropical Cyclone' }) : e));
      if (newEvent.deployment === 'Deployed') setActiveEventId(newEvent.id);
      addNotification('Event Edited', `Event ${newEvent.name} has been updated.`, 'info');
      showToast('Event edited successfully.', 'success');
      setIsEditingEvent(false);
      resetNewEventForm();
      setShowAddModal(false);
      return;
    }
    const newId = Math.max(...events.map(e => e.id), 0) + 1;
    const formattedDate = newEvent.startDateTime ? new Date(newEvent.startDateTime).toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' }) : new Date().toLocaleDateString();
    const newStatus = newEvent.deployment === 'Deployed' ? 'active' : 'pending';
    const provinces = newEvent.sendToAllUsers ? allProvinces : newEvent.provinces;
    setEvents([{ ...newEvent, id: newId, date: formattedDate, status: newStatus, type: 'Tropical Cyclone', provinces, rejectionReason: '' }, ...events]);
    if (newEvent.deployment === 'Deployed') setActiveEventId(newId);
    resetPSTODataForNewEvent();
    addNotification('Event Created', `New event "${newEvent.name}" has been created. PSTO data has been reset.`, 'success');
    resetNewEventForm();
    setShowAddModal(false);
    showToast('Event created and PSTO data reset.', 'success');
  };

  const resetNewEventForm = () => {
    setNewEvent({
      id: null, name: '', startDateTime: '', endDateTime: '',
      alertLevel: '', category: '', deployment: 'Draft', provinces: [],
      sendToAllUsers: false, reportLink: '', trackPositions: '', intensity: '',
      related_incidents: 0, remark_related_incidents: '', casualties: 0, remark_casualties: '',
      power_status: '', remark_power_status: '', communication_lines: '', remark_communication_lines: '',
      damage_facilities: '', remark_damage_facilities: '', work_suspension: false,
      remark_work_suspension: '', assistance_provided: '', remark_assistance_provided: '',
      imageUrl: '', status: 'pending', rejectionReason: ''
    });
  };

  const handleEditEvent = (event) => {
    setNewEvent({
      id: event.id, name: event.name || '', startDateTime: event.startDateTime || '', endDateTime: event.endDateTime || '',
      alertLevel: event.alertLevel || '', category: event.category || event.type || '',
      deployment: event.deployment || 'Draft', provinces: event.provinces ? [...event.provinces] : [],
      sendToAllUsers: event.provinces?.length === allProvinces.length, reportLink: event.reportLink || '',
      trackPositions: event.trackPositions || '', intensity: event.intensity || '',
      related_incidents: event.related_incidents ?? 0, remark_related_incidents: event.remark_related_incidents || '',
      casualties: event.casualties ?? 0, remark_casualties: event.remark_casualties || '',
      power_status: event.power_status || '', remark_power_status: event.remark_power_status || '',
      communication_lines: event.communication_lines || '', remark_communication_lines: event.remark_communication_lines || '',
      damage_facilities: event.damage_facilities || '', remark_damage_facilities: event.remark_damage_facilities || '',
      work_suspension: event.work_suspension || false, remark_work_suspension: event.remark_work_suspension || '',
      assistance_provided: event.assistance_provided || '', remark_assistance_provided: event.remark_assistance_provided || '',
      imageUrl: event.imageUrl || '', status: event.status || 'pending', rejectionReason: event.rejectionReason || ''
    });
    setIsEditingEvent(true);
    setShowAddModal(true);
    setShowDetailsModal(false);
  };

  const handleDeleteEvent = (eventId) => {
    if (!window.confirm('Delete this event? This action cannot be undone.')) return;
    const eventName = events.find(e => e.id === eventId)?.name;
    setEvents(events.filter(e => e.id !== eventId));
    if (activeEventId === eventId) setActiveEventId(null);
    setShowDetailsModal(false);
    addNotification('Event Deleted', `Event ${eventName} has been permanently deleted.`, 'error');
    showToast('Event deleted.', 'error');
  };

  const filteredEvents = events.filter(event => {
    const term = searchTerm.toLowerCase();
    const matchSearch = event.name.toLowerCase().includes(term) || event.alertLevel?.toLowerCase().includes(term) ||
      event.date?.toLowerCase().includes(term) || event.status?.toLowerCase().includes(term) ||
      (event.category || '').toLowerCase().includes(term);
    if (statusFilter === 'all') return matchSearch;
    return matchSearch && event.status === statusFilter;
  });

  // User management
  const validateEmail = (email) => /\S+@\S+\.\S+/.test(email);
  const validatePassword = (pwd) => pwd.length >= 6;

  const handleSaveUser = () => {
    if (!userForm.name || !userForm.email || (!userForm.password && !isEditingUser)) { showToast('Name, email, and password are required.', 'warning'); return; }
    if (!validateEmail(userForm.email)) { showToast('Invalid email format.', 'warning'); return; }
    if (!isEditingUser && !validatePassword(userForm.password)) { showToast('Password must be at least 6 characters.', 'warning'); return; }
    if (isEditingUser) {
      setUsers(users.map(u => u.id === userForm.id ? { ...u, ...userForm, password: userForm.password || u.password } : u));
      addNotification('User Updated', `User ${userForm.name} has been updated.`, 'info');
      showToast('User updated.', 'success');
    } else {
      const newId = Math.max(0, ...users.map(u => u.id)) + 1;
      setUsers([{ ...userForm, id: newId }, ...users]);
      addNotification('User Created', `New user ${userForm.name} (${userForm.role}) has been created.`, 'success');
      showToast('User created.', 'success');
    }
    setShowUserModal(false);
    setIsEditingUser(false);
    setUserForm({ id: null, name: '', email: '', office: selectedOffice || 'PSTO-La Union', role: 'USER', status: 'Active', password: '' });
  };

  const handleDeleteUser = (userId) => {
    if (!window.confirm('Delete this user? This action cannot be undone.')) return;
    const userName = users.find(u => u.id === userId)?.name;
    setUsers(users.filter(u => u.id !== userId));
    addNotification('User Deleted', `User ${userName} has been deleted.`, 'error');
    showToast('User deleted.', 'error');
  };

  // Report generation
  const buildReportHtml = () => {
    const generatedAt = new Date().toLocaleString();
    const reportOffices = Object.entries(officesData);
    const summaryRows = reportOffices.map(([officeName, officeData]) => {
      const warningTags = Object.entries(officeData.warning_signals || {}).map(([mun, signal]) => `${mun} (Signal ${signal})`).join('; ') || 'None';
      return `<tr><td style="border:1px solid #000;padding:8px;">${officeName}</td><td style="border:1px solid #000;padding:8px;">${warningTags}</td><td style="border:1px solid #000;padding:8px;">${officeData.general_weather || 'N/A'}</td></tr>`;
    }).join('');
    const footerNarrative = Object.values(officesData).map(office => office.remark).filter(Boolean).join(' ') || 'No additional remarks.';

    return `
      <!DOCTYPE html>
      <html>
      <head><meta charset="UTF-8"><title>DOST-1 Situational Report</title>
      <style>body{font-family:Arial;margin:20px}table{width:100%;border-collapse:collapse;margin:10px 0}th,td{border:1px solid #000;padding:8px}th{background:#f0f0f0}</style>
      </head>
      <body>
        <h1>SITUATIONAL REPORT</h1>
        <p><strong>Event:</strong> ${activeEvent?.name || 'None'} | <strong>Generated:</strong> ${generatedAt}</p>
        </table><thead><tr><th>OFFICE</th><th>SIGNALS</th><th>WEATHER</th></tr></thead><tbody>${summaryRows}</tbody></table>
        <p><strong>Summary:</strong> ${footerNarrative}</p>
        <p>Prepared by: DOST 1 DRRM Unit</p>
      </body>
      </html>
    `;
  };

  const handleGenerateReport = () => {
    const reportHtml = buildReportHtml();
    const printWindow = window.open('', '_blank');
    if (!printWindow) {
      showToast('Pop-up blocked. Allow pop-ups to generate the report.', 'warning');
      return;
    }
    printWindow.document.write(reportHtml);
    printWindow.document.close();
  };

  const handleDownloadDoc = () => {
    const reportHtml = buildReportHtml();
    const blob = new Blob([reportHtml], { type: 'application/msword' });
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `SITREP_${activeEvent?.name || 'NO_EVENT'}_${new Date().toISOString().slice(0,19)}.doc`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  const handleExportExcel = () => {
    const sheetData = [['PSTO Office', 'Warning Signals', 'General Weather', 'Related Incidents', 'Casualties', 'Power Status', 'Communication', 'Damage', 'Work Suspension', 'Assistance', 'Remarks']];
    Object.entries(officesData).forEach(([office, data]) => {
      const signals = Object.entries(data.warning_signals || {}).map(([mun, sig]) => `${mun}: ${sig}`).join('; ') || 'None';
      sheetData.push([office, signals, data.general_weather || '', data.related_incidents ?? 0, data.casualties ?? 0, data.power_status || '', data.communication_lines || '', data.damage_facilities || '', data.work_suspension ? 'Yes' : 'No', data.assistance_provided || '', data.remark || '']);
    });
    const ws = XLSX.utils.aoa_to_sheet(sheetData);
    const wb = XLSX.utils.book_new();
    XLSX.utils.book_append_sheet(wb, ws, 'PSTO_Report');
    XLSX.writeFile(wb, `DOST1_Report_${new Date().toISOString().slice(0,19)}.xlsx`);
    showToast('Excel report exported successfully.', 'success');
  };

  // PSTO data display
  const regionSummary = {
    offices: Object.keys(officesData).length,
    incidents: Object.values(officesData).reduce((sum, office) => sum + (office.related_incidents || 0), 0),
    casualties: Object.values(officesData).reduce((sum, office) => sum + (office.casualties || 0), 0),
    suspensions: Object.values(officesData).filter(office => office.work_suspension).length,
  };

  const currentOfficeData = selectedOffice === 'PSTO-Region-1' ? {
    general_weather: liveWeather ? `${liveWeather.condition}, ${liveWeather.temp}°C` : 'Fetching live weather...',
    related_incidents: regionSummary.incidents,
    casualties: regionSummary.casualties,
    warning_signals: {},
    power_status: 'Region summary',
    communication_lines: 'Region summary',
    damage_facilities: 'Region summary',
    work_suspension: false,
    assistance_provided: 'Region summary',
    remark: 'Region-wide situation overview.',
    remark_related_incidents: '',
    remark_casualties: '',
    remark_power_status: '',
    remark_communication_lines: '',
    remark_damage_facilities: '',
    remark_work_suspension: '',
    remark_assistance_provided: '',
    municipalities: []
  } : officesData[selectedOffice];

  const displayWeather = liveWeather ? `${liveWeather.condition}, ${liveWeather.temp}°C, Wind ${liveWeather.windSpeed} km/h` : (weatherLoading ? 'Loading live weather...' : currentOfficeData.general_weather);
  const displayEvent = editMode ? formData : currentOfficeData;
  const municipalitiesList = displayEvent?.municipalities || [];

  const handleOfficeClick = (officeName) => { if (!isUser) { setSelectedOffice(officeName); setEditMode(false); } };
  const handleEditToggle = () => { if (!editMode) setFormData({ ...currentOfficeData, municipalities: [...currentOfficeData.municipalities] }); setEditMode(!editMode); };
  const handleSave = () => { setOfficesData({ ...officesData, [selectedOffice]: formData }); setEditMode(false); addNotification('PSTO Data Saved', `${selectedOffice} data was manually edited.`, 'info'); showToast('PSTO data saved.', 'success'); };
  const handleInputChange = (e) => { const { name, value, type, checked } = e.target; setFormData({ ...formData, [name]: type === 'checkbox' ? checked : value }); };
  const handleSignalChange = (municipality, value) => { setFormData({ ...formData, warning_signals: { ...formData.warning_signals, [municipality]: parseInt(value) } }); };
  const handleAddMunicipality = () => { if (newMunicipality.trim() && !formData.municipalities.includes(newMunicipality)) { setFormData({ ...formData, municipalities: [...formData.municipalities, newMunicipality], warning_signals: { ...formData.warning_signals, [newMunicipality]: newSignal } }); setNewMunicipality(''); setNewSignal(1); } };
  const handleRemoveMunicipality = (municipality) => { const updatedMunicipalities = formData.municipalities.filter(m => m !== municipality); const updatedSignals = { ...formData.warning_signals }; delete updatedSignals[municipality]; setFormData({ ...formData, municipalities: updatedMunicipalities, warning_signals: updatedSignals }); };
  const handleOpenAddModal = () => { if (!canEditEvents) return; setShowAddModal(true); };
  const handleViewEvent = (event) => { setSelectedEvent(event); setShowDetailsModal(true); };
  const handleCloseDetailsModal = () => { setShowDetailsModal(false); setSelectedEvent(null); };
  const handleSaveReportLink = () => { const updatedEvents = events.map(event => event.id === selectedEvent.id ? { ...event, reportLink: reportLinkInput } : event); setEvents(updatedEvents); setSelectedEvent({ ...selectedEvent, reportLink: reportLinkInput }); setIsEditingReportLink(false); setReportLinkInput(''); };
  const openImageModal = (src) => { setImageModalSrc(src); setShowImageModal(true); };
  const closeImageModal = () => { setShowImageModal(false); setImageModalSrc(''); };
  const getAlertColor = (level) => ({ RED:'#dc3545', BLUE:'#007bff', WHITE:'#6c757d' }[level] || '#28a745');
  const getStatusColor = (status) => ({ active:'#28a745', approved:'#0d6efd', pending:'#ffc107', draft:'#6c757d', rejected:'#dc3545', archived:'#adb5bd' }[status] || '#6c757d');
  const getEventStatusLabel = (event) => {
    if (event.deployment === 'Deployed') return 'Active';
    if (event.status === 'pending') return 'Pending Approval';
    if (event.status === 'approved') return 'Approved';
    if (event.status === 'rejected') return 'Rejected';
    if (event.status === 'archived') return 'Archived';
    return event.deployment || 'Draft';
  };

  const unreadCount = notifications.filter(n => !n.read).length;
  const toggleSection = (section) => { setExpandedSections(prev => ({ ...prev, [section]: !prev[section] })); };

  if (loading) {
    return (
      <div className="loading-container">
        <div className="spinner"></div>
        <p>Loading dashboard from cloud...</p>
      </div>
    );
  }

  // ----------------------------- RENDER COMPONENTS -----------------------------
  const DashboardContent = () => (
    <div>
      {toast.visible && (
        <div className={`toast-banner toast-${toast.type}`}>
          <span>{toast.message}</span>
          <button className="toast-close" onClick={() => setToast(prev => ({ ...prev, visible: false }))}>×</button>
        </div>
      )}
      <div className="top-info-bar">
        <div className="top-info-item top-info-main"><span className="top-info-label">Current Event</span><span className="top-info-value">{activeEvent ? activeEvent.name : 'No Active Typhoon'}</span></div>
        <div className="top-info-item"><span className="top-info-label">Category</span><span className="top-info-value">{activeEvent?.category || '—'}</span></div>
        <div className="top-info-item"><span className="top-info-label">Alert Level</span><span className="top-info-value">{activeEvent?.alertLevel || '—'}</span></div>
        <div className="top-info-item"><span className="top-info-label">Live Weather</span><span className="top-info-value">{displayWeather}</span></div>
      </div>
      <div className="info-bar">
        <div className="info-item"><span className="info-value">Region 1</span></div>
        <div className="info-item"><span className="info-label">Current Weather:</span><span className="info-value">{displayWeather}</span></div>
        <div className="info-item"><span className="info-label">Active Event:</span><span className="info-value">{activeEvent ? activeEvent.name : 'None'}</span></div>
      </div>
      <div className="notification-banner">
        <span className="notification-badge">SYSTEM NOTICE</span>
        <span>{activeEvent ? `Active tropical cyclone ${activeEvent.name} (${activeEvent.alertLevel}) is being monitored.` : 'No active tropical cyclone at the moment. Systems are stable.'}</span>
        <div style={{ display: 'flex', gap: '10px', marginLeft: '16px', flexWrap: 'wrap' }}>
          <button className="secondary-btn" onClick={handleGenerateReport}>📄 Generate Report</button>
          <button className="secondary-btn" onClick={handleDownloadDoc}>📥 Download DOC</button>
          <button className="secondary-btn" onClick={handleExportExcel}>📊 Export Excel</button>
          <button 
            className="secondary-btn" 
            onClick={async () => {
              setSyncing(true);
              await syncService.syncData();
              showToast('Data synced from cloud!', 'success');
            }}
            disabled={syncing}
            style={{ background: '#3b82f6' }}
          >
            {syncing ? '🔄 Syncing...' : '🔄 Sync Now'}
          </button>
          {lastSync && (
            <span style={{ fontSize: '11px', marginLeft: '10px', color: '#666', alignSelf: 'center' }}>
              Last sync: {lastSync.toLocaleTimeString()}
            </span>
          )}
        </div>
      </div>
      <div className="psto-selector-section">
        <div className="psto-section-header"><h2>{isUser && currentUser?.office ? '🏢 Your PSTO Office' : '🏢 Select PSTO Office'}</h2></div>
        <div className="psto-selector-grid">
          {isUser && currentUser?.office ? (
            <div className="psto-selector-card active"><div className="psto-selector-name">{currentUser.office}</div><div className="psto-selector-stats"><span>📊 {officesData[currentUser.office]?.related_incidents ?? 0}</span><span>⚠️ {officesData[currentUser.office]?.casualties ?? 0}</span></div></div>
          ) : (
            <>
              <div className={`psto-selector-card ${selectedOffice === 'PSTO-Region-1' ? 'active' : ''}`} onClick={() => handleOfficeClick('PSTO-Region-1')}><div className="psto-selector-name">PSTO Region 1</div><div className="psto-selector-stats"><span>📊 {regionSummary.incidents}</span><span>⚠️ {regionSummary.casualties}</span></div></div>
              {Object.keys(officesData).map(office => (
                <div key={office} className={`psto-selector-card ${selectedOffice === office ? 'active' : ''}`} onClick={() => handleOfficeClick(office)}><div className="psto-selector-name">{office}</div><div className="psto-selector-stats"><span>📊 {officesData[office].related_incidents}</span><span>⚠️ {officesData[office].casualties}</span></div></div>
              ))}
            </>
          )}
        </div>
      </div>
      <div className="edit-controls-bar">
        <div><strong>Current PSTO:</strong> {selectedOffice}</div>
        <div className="edit-buttons">
          {!isUser && <button onClick={handleEditToggle}>{editMode ? 'Cancel' : '✏️ Edit PSTO Data'}</button>}
          {isUser && <button className="success" onClick={openReportModal}>📤 Submit Report</button>}
          {editMode && <button className="success" onClick={handleSave}>💾 Save Changes</button>}
        </div>
      </div>
      <div className="main-grid">
        <div className="card warning-card">
          <div className="warning-card-header"><h3 className="warning-header"><span className="warning-icon">⚠️</span> TROPICAL CYCLONE WARNING SIGNAL</h3></div>
          <div className="warning-card-body">
            {editMode ? (
              <div className="improved-edit-form">
                <div className="edit-section">
                  <div className="edit-section-header" onClick={() => toggleSection('warningSignals')}><h4>📡 Warning Signals</h4><span>{expandedSections.warningSignals ? '▼' : '►'}</span></div>
                  {expandedSections.warningSignals && (
                    <div className="edit-section-content">
                      {municipalitiesList.map(mun => (
                        <div key={mun} className="signal-edit-row">
                          <span className="municipality-name">{mun}</span>
                          <select value={displayEvent.warning_signals?.[mun] || 0} onChange={(e) => handleSignalChange(mun, e.target.value)}>
