                      <div className="form-row"><div className="form-group"><label>Casualties</label><input type="number" name="casualties" value={displayEvent.casualties} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_casualties" value={displayEvent.remark_casualties || ''} onChange={handleInputChange} /></div></div>
                      <div className="form-row"><div className="form-group"><label>Power Status</label><input type="text" name="power_status" value={displayEvent.power_status} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_power_status" value={displayEvent.remark_power_status || ''} onChange={handleInputChange} /></div></div>
                      <div className="form-row"><div className="form-group"><label>Communication Lines</label><input type="text" name="communication_lines" value={displayEvent.communication_lines} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_communication_lines" value={displayEvent.remark_communication_lines || ''} onChange={handleInputChange} /></div></div>
