                      <div className="form-row"><div className="form-group checkbox-group"><label><input type="checkbox" name="work_suspension" checked={displayEvent.work_suspension} onChange={handleInputChange} /> Work Suspension</label></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_work_suspension" value={displayEvent.remark_work_suspension || ''} onChange={handleInputChange} /></div></div>
                      <div className="form-row"><div className="form-group"><label>Assistance Provided</label><input type="text" name="assistance_provided" value={displayEvent.assistance_provided} onChange={handleInputChange} /></div><div className="form-group"><label>Remarks</label><input type="text" name="remark_assistance_provided" value={displayEvent.remark_assistance_provided || ''} onChange={handleInputChange} /></div></div>
