              <div key={mun} className="signal-edit-row"><span>{mun}</span><select value={reportFormData.warning_signals[mun] || 0} onChange={(e) => handleReportSignalChange(mun, e.target.value)}><option value={0}>No Signal</option><option value={1}>#1</option><option value={2}>#2</option><option value={3}>#3</option><option value={4}>#4</option><option value={5}>#5</option></select><button className="remove-mun-btn" onClick={() => handleReportRemoveMunicipality(mun)}>🗑️</button></div>
            ))}
            <div className="add-municipality-row"><input placeholder="New municipality" value={newMunicipality} onChange={(e) => setNewMunicipality(e.target.value)} /><select value={newSignal} onChange={(e) => setNewSignal(parseInt(e.target.value))}><option>#1</option><option>#2</option><option>#3</option><option>#4</option><option>#5</option></select><button className="add-mun-btn" onClick={handleReportAddMunicipality}>+ Add</button></div>
          </div>
          <div className="form-group"><label>General Weather</label><input type="text" value={reportFormData.general_weather} onChange={(e) => handleReportFieldChange('general_weather', e.target.value)} /></div>
          <div className="form-row"><div className="form-group"><label>Related Incidents</label><input type="number" value={reportFormData.related_incidents} onChange={(e) => handleReportFieldChange('related_incidents', parseInt(e.target.value) || 0)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_related_incidents || ''} onChange={(e) => handleReportFieldChange('remark_related_incidents', e.target.value)} /></div></div>
          <div className="form-row"><div className="form-group"><label>Casualties</label><input type="number" value={reportFormData.casualties} onChange={(e) => handleReportFieldChange('casualties', parseInt(e.target.value) || 0)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_casualties || ''} onChange={(e) => handleReportFieldChange('remark_casualties', e.target.value)} /></div></div>
          <div className="form-row"><div className="form-group"><label>Power Status</label><input type="text" value={reportFormData.power_status} onChange={(e) => handleReportFieldChange('power_status', e.target.value)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_power_status || ''} onChange={(e) => handleReportFieldChange('remark_power_status', e.target.value)} /></div></div>
          <div className="form-row"><div className="form-group"><label>Communication Lines</label><input type="text" value={reportFormData.communication_lines} onChange={(e) => handleReportFieldChange('communication_lines', e.target.value)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_communication_lines || ''} onChange={(e) => handleReportFieldChange('remark_communication_lines', e.target.value)} /></div></div>
          <div className="form-row"><div className="form-group"><label>Damage to Facilities</label><input type="text" value={reportFormData.damage_facilities} onChange={(e) => handleReportFieldChange('damage_facilities', e.target.value)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_damage_facilities || ''} onChange={(e) => handleReportFieldChange('remark_damage_facilities', e.target.value)} /></div></div>
          <div className="form-row"><div className="form-group checkbox-group"><label><input type="checkbox" checked={reportFormData.work_suspension} onChange={(e) => handleReportFieldChange('work_suspension', e.target.checked)} /> Work Suspension</label></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_work_suspension || ''} onChange={(e) => handleReportFieldChange('remark_work_suspension', e.target.value)} /></div></div>
          <div className="form-row"><div className="form-group"><label>Assistance Provided</label><input type="text" value={reportFormData.assistance_provided} onChange={(e) => handleReportFieldChange('assistance_provided', e.target.value)} /></div><div className="form-group"><label>Remarks</label><input type="text" value={reportFormData.remark_assistance_provided || ''} onChange={(e) => handleReportFieldChange('remark_assistance_provided', e.target.value)} /></div></div>
          <div className="modal-buttons"><button className="success" onClick={submitReport}>Submit for Approval</button><button onClick={() => setShowReportModal(false)}>Cancel</button></div>
        </div>
      </div>
    );
  };

  const UsersContent = () => {
    const filteredUsers = users.filter(u => u.name.toLowerCase().includes(userSearchTerm.toLowerCase()) || u.email.toLowerCase().includes(userSearchTerm.toLowerCase()) || u.role.toLowerCase().includes(userSearchTerm.toLowerCase()));
    return (
      <div className="events-management users-management">
        <div className="events-header">
          <h1>User Management</h1>
          <div className="header-actions">
            <div className="search-box"><span className="search-icon">🔍</span><input type="text" placeholder="Search users..." value={userSearchTerm} onChange={(e) => setUserSearchTerm(e.target.value)} /></div>
            <button className="new-event-btn" onClick={() => { setUserForm({ id: null, name: '', email: '', office: selectedOffice, role: 'USER', status: 'Active', password: '' }); setIsEditingUser(false); setShowUserModal(true); }}>+ New User</button>
          </div>
        </div>
        <div className="events-table-container">
          <table className="events-table users-table">
            <thead>
              <tr><th>Name</th><th>Email</th><th>Office</th><th>Role</th><th>Status</th><th>Actions</th></tr>
            </thead>
            <tbody>
              {filteredUsers.map(user => (
                <tr key={user.id}>
                  <td>{user.name}</td>
                  <td>{user.email}</td>
                  <td>{user.office}</td>
                  <td><span className="role-badge">{user.role}</span></td>
                  <td>{user.status}</td>
                  <td className="actions-cell">
                    <button className="view-btn" onClick={() => { setUserForm(user); setIsEditingUser(true); setShowUserModal(true); }}>Edit</button>
                    <button className="deploy-btn" onClick={() => handleDeleteUser(user.id)}>Delete</button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
        {showUserModal && (
          <div className="modal-overlay" onClick={() => setShowUserModal(false)}>
            <div className="modal-content" onClick={e => e.stopPropagation()}>
              <div className="modal-header"><h3>{isEditingUser ? 'Edit User' : 'Create User'}</h3><button className="modal-close" onClick={() => setShowUserModal(false)}>×</button></div>
              <div className="form-group"><label>Name</label><input type="text" value={userForm.name} onChange={(e) => setUserForm({...userForm, name: e.target.value})} /></div>
              <div className="form-group"><label>Email</label><input type="email" value={userForm.email} onChange={(e) => setUserForm({...userForm, email: e.target.value})} /></div>
              <div className="form-group"><label>Office</label><select value={userForm.office} onChange={(e) => setUserForm({...userForm, office: e.target.value})}>{['PSTO-Ilocos Norte','PSTO-Ilocos Sur','PSTO-La Union','PSTO-Pangasinan'].map(off => <option key={off}>{off}</option>)}</select></div>
              <div className="form-group"><label>Password {isEditingUser && '(leave blank to keep current)'}</label><input type="password" value={userForm.password} onChange={(e) => setUserForm({...userForm, password: e.target.value})} /></div>
              <div className="form-group"><label>Role</label><select value={userForm.role} onChange={(e) => setUserForm({...userForm, role: e.target.value})}><option value="SADMIN">SADMIN</option><option value="ADMIN">ADMIN</option><option value="USER">USER</option></select></div>
              <div className="form-group"><label>Status</label><select value={userForm.status} onChange={(e) => setUserForm({...userForm, status: e.target.value})}><option>Active</option><option>Inactive</option></select></div>
              <div className="modal-buttons"><button className="success" onClick={handleSaveUser}>{isEditingUser ? 'Save' : 'Create'}</button><button onClick={() => setShowUserModal(false)}>Cancel</button></div>
            </div>
          </div>
        )}
      </div>
    );
  };

  const NotificationsContent = () => {
    return (
      <div className="events-management">
        <div className="events-header">
          <h1>Notifications {unreadCount > 0 && `(${unreadCount} new)`}</h1>
          <div className="header-actions"><button className="new-event-btn" onClick={clearAllNotifications}>Clear All</button></div>
        </div>
        <div className="events-subtitle">System events, report updates, and alerts</div>
        <div className="notifications-list">
          {notifications.length === 0 ? (
            <div className="no-notifications">No notifications yet.</div>
          ) : (
            notifications.map(notif => (
              <div key={notif.id} className={`notification-item ${!notif.read ? 'unread' : ''} ${notif.type}`} onClick={() => markNotificationRead(notif.id)}>
                <div className="notification-header"><span className="notification-title">{notif.title}</span><span className="notification-time">{new Date(notif.timestamp).toLocaleString()}</span></div>
                <div className="notification-message">{notif.message}</div>
              </div>
            ))
          )}
        </div>
      </div>
    );
  };

  // ----------------------------- MAIN RENDER -----------------------------
  return (
    <div className="dashboard-container">
      <div className="sidebar-new">
        <div className="sidebar-logo"><h2>DOST Region 1</h2><p>Disaster Management</p></div>
        <nav className="sidebar-nav">
          <div className={`nav-item ${activeMenu === 'dashboard' ? 'active' : ''}`} onClick={() => setActiveMenu('dashboard')}><span className="nav-icon">📊</span><span>Dashboard</span></div>
          <div className={`nav-item ${activeMenu === 'typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('typhoon')}><span className="nav-icon">🌊</span><span>Typhoon</span></div>
          <div className={`nav-item ${activeMenu === 'live-typhoon' ? 'active' : ''}`} onClick={() => setActiveMenu('live-typhoon')}><span className="nav-icon">🗺️</span><span>Live Typhoon (Panahon)</span></div>
          <div className={`nav-item ${activeMenu === 'notifications' ? 'active' : ''}`} onClick={() => setActiveMenu('notifications')}><span className="nav-icon">🔔</span><span>Notifications {unreadCount > 0 && `(${unreadCount})`}</span></div>
          {canApproveReports && <div className={`nav-item ${activeMenu === 'pending-reports' ? 'active' : ''}`} onClick={() => setActiveMenu('pending-reports')}><span className="nav-icon">📋</span><span>Pending Reports</span></div>}
          {canManageUsers && <div className={`nav-item ${activeMenu === 'users' ? 'active' : ''}`} onClick={() => setActiveMenu('users')}><span className="nav-icon">👥</span><span>Users</span></div>}
        </nav>
        <div className="sidebar-footer">
          <div className="user-info"><div className="user-greeting">Hello, {currentUser?.name || 'Admin'}</div><div className="user-role">{isSuperAdmin ? 'SUPER ADMIN' : (isAdmin ? 'ADMIN' : 'USER')}</div></div>
          <div className="user-actions"><div className="action-item logout" onClick={onLogout}>🚪 Logout</div></div>
        </div>
      </div>
      <div className="main-content">
        {isSuperAdmin && (
          <div className="admin-toolbar">
            <button onClick={resetToDefaultData}>Reset to Default Data</button>
            <button onClick={exportData}>Export Data</button>
            <label className="import-btn"><input type="file" onChange={importData} style={{ display: 'none' }} />Import Data</label>
          </div>
        )}
        {activeMenu === 'dashboard' && <DashboardContent />}
        {activeMenu === 'typhoon' && <TyphoonContent />}
        {activeMenu === 'live-typhoon' && (
          <div className="forecast-section card">
            <h1>Live Typhoon (Panahon)</h1>
            <div className="windy-embed-container"><iframe title="Panahon" src="https://www.panahon.gov.ph/" frameBorder="0" allowFullScreen /></div>
          </div>
        )}
        {activeMenu === 'notifications' && <NotificationsContent />}
        {activeMenu === 'pending-reports' && canApproveReports && <PendingReportsContent />}
        {activeMenu === 'users' && canManageUsers && <UsersContent />}
      </div>
      {showReportModal && <SubmitReportModal />}
      {showReportReviewModal && <ReportReviewModal />}
      {showRejectModal && (
        <div className="modal-overlay" onClick={() => setShowRejectModal(false)}>
          <div className="modal-content">
            <h3>Reject Event</h3>
            <textarea className="reject-reason-textarea" placeholder="Provide reason for rejection..." value={rejectReason} onChange={(e) => setRejectReason(e.target.value)} />
            <div className="modal-buttons"><button className="danger" onClick={confirmRejectEvent}>Confirm Rejection</button><button onClick={() => setShowRejectModal(false)}>Cancel</button></div>
          </div>
        </div>
      )}
      {showImageModal && imageModalSrc && (
        <div className="modal-overlay" onClick={closeImageModal}>
          <div className="modal-content image-modal-content" onClick={e => e.stopPropagation()}>
            <button className="modal-close" onClick={closeImageModal}>×</button>
            <img src={imageModalSrc} alt="Enlarged" className="image-modal-img" />
          </div>
        </div>
      )}
    </div>
  );
};

export default Dashboard;
